static bool histogram_equalization(uint8_t *buf, size_t len) {
    uint32_t hist[256] = {0};
    for (size_t i = 0; i < len; i++) {
        hist[buf[i]]++;
    }

    uint32_t cdf[256] = {0};
    cdf[0] = hist[0];
    for (int i = 1; i < 256; i++) {
        cdf[i] = cdf[i - 1] + hist[i];
    }

    uint32_t cdf_min = 0;
    for (int i = 0; i < 256; i++) {
        if (cdf[i] != 0) {
            cdf_min = cdf[i];
            break;
        }
    }

    uint8_t lut[256];
    uint32_t denom = (uint32_t)len - cdf_min;
    if (denom == 0) denom = 1; 

    for (int i = 0; i < 256; i++) {
        if (cdf[i] == 0) {
            lut[i] = 0;
        } else {
            uint32_t val = ((cdf[i] - cdf_min) * 255 + denom / 2) / denom;
            lut[i] = (uint8_t)(val > 255 ? 255 : val);
        }
    }

    for (size_t i = 0; i < len; i++) {
        buf[i] = lut[buf[i]];
    }
    return true;
}

static void print_hex(const char *label, const uint8_t *buf, size_t len)
{
    printf("\n=== %s ===\n", label);
    for (size_t i = 0; i < len; i++) {
        printf("0x%02X, ", buf[i]);
        if ((i + 1) % 512 == 0) {
            vTaskDelay(pdMS_TO_TICKS(10));
        }
    }
    printf("\n=== FIN %s ===\n", label);
}

void app_main(void) {
    size_t len = sizeof(imagen_original);
    uint8_t *eq_buf = (uint8_t *)malloc(len);
    memcpy(eq_buf, imagen_original, len);
    
    histogram_equalization(eq_buf, len);
    print_hex("IMAGEN ECUALIZADA", eq_buf, len);
    free(eq_buf);
}